    static func countries(for difficulty: Difficulty) -> [Country] {
        switch difficulty {
        case .easy:        return all.filter { $0.difficulty == .easy }
        case .medium:      return all.filter { $0.difficulty == .easy || $0.difficulty == .medium }
        case .hard:        return all.filter { $0.difficulty == .medium || $0.difficulty == .hard }
        case .worldMaster: return all
        }
    }

    static func wrongOptions(for correct: Country, in pool: [Country], count: Int = 3) -> [Country] {
        let candidates = pool.filter { $0.id != correct.id }.shuffled()
        return Array(candidates.prefix(count))
    }
